package com.example.usage;

import com.seed.bytesUpload.SeedBytesUploadClient;
import com.seed.bytesUpload.resources.service.requests.UploadWithQueryParamsRequest;

public class Example {
    public static void main(String[] args) {
        SeedBytesUploadClient client = SeedBytesUploadClient
            .builder()
            .build();

        client.service().uploadWithQueryParams(
            UploadWithQueryParamsRequest
                .builder()
                .model("nova-2")
                .body("".getBytes())
                .build()
        );
    }
}

